import React, { useEffect, useState } from 'react';
import api from '../api';

const PatientList = () => {
  const [patients, setPatients] = useState<any[]>([]);
  // State para mahibaloan kung kinsa nga row ang gi-edit
  const [editingId, setEditingId] = useState<number | null>(null);
  const [editName, setEditName] = useState('');
  const [editEmail, setEditEmail] = useState('');

  const fetchPatients = () => {
    api.get('patients/').then((res: any) => setPatients(res.data));
  };

  useEffect(() => { fetchPatients(); }, []);

  // Inig pindot sa Edit button
  const startEdit = (p: any) => {
    setEditingId(p.patient_id);
    setEditName(p.full_name);
    setEditEmail(p.email);
  };

  // Inig pindot sa Save
  const handleUpdate = async (id: number) => {
    try {
      await api.put(`patients/${id}/`, { 
        full_name: editName, 
        email: editEmail 
      });
      setEditingId(null); // I-close ang edit mode
      fetchPatients();    // I-refresh ang listahan
    } catch (err) {
      console.error("Error updating:", err);
    }
  };

  return (
    <div className="bg-white rounded-xl shadow-md overflow-hidden">
      <table className="min-w-full divide-y divide-gray-200">
        <thead className="bg-gray-50">
          <tr>
            <th className="px-6 py-3 text-left text-xs font-bold text-gray-500 uppercase">Name</th>
            <th className="px-6 py-3 text-left text-xs font-bold text-gray-500 uppercase">Email</th>
            <th className="px-6 py-3 text-center text-xs font-bold text-gray-500 uppercase">Actions</th>
          </tr>
        </thead>
        <tbody className="divide-y divide-gray-100">
          {patients.map((p: any) => (
            <tr key={p.patient_id}>
              {editingId === p.patient_id ? (
                // --- KINI ANG EDIT MODE (Naay Input) ---
                <>
                  <td className="px-6 py-4">
                    <input className="border p-1 w-full rounded" value={editName} onChange={e => setEditName(e.target.value)} />
                  </td>
                  <td className="px-6 py-4">
                    <input className="border p-1 w-full rounded" value={editEmail} onChange={e => setEditEmail(e.target.value)} />
                  </td>
                  <td className="px-6 py-4 text-center space-x-2">
                    <button onClick={() => handleUpdate(p.patient_id)} className="text-green-600 font-bold">Save</button>
                    <button onClick={() => setEditingId(null)} className="text-gray-500">Cancel</button>
                  </td>
                </>
              ) : (
                // --- KINI ANG VIEW MODE (Text Ra) ---
                <>
                  <td className="px-6 py-4 text-sm text-gray-800">{p.full_name}</td>
                  <td className="px-6 py-4 text-sm text-gray-600">{p.email}</td>
                  <td className="px-6 py-4 text-center space-x-4">
                    <button onClick={() => startEdit(p)} className="text-blue-600 hover:underline">Edit</button>
                    <button onClick={() => {/* handleDelete logic here */}} className="text-red-600 hover:underline">Delete</button>
                  </td>
                </>
              )}
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default PatientList;
